package ru.memearena.media.application;
import org.slf4j.*; import org.springframework.http.HttpStatus; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import org.springframework.web.multipart.MultipartFile; import ru.memearena.error.*; import ru.memearena.media.domain.*; import ru.memearena.media.infrastructure.MediaAssetRepository; import ru.memearena.meme.domain.ModerationStatus; import ru.memearena.meme.infrastructure.MemeRepository; import ru.memearena.user.infrastructure.UserProfileRepository; import java.io.*; import java.time.*; import java.util.*;
@Service public class MediaService { private static final Logger log=LoggerFactory.getLogger(MediaService.class); private final MediaAssetRepository repo; private final UserProfileRepository users; private final MemeRepository memes; private final MediaStorage storage; private final Clock clock; public MediaService(MediaAssetRepository repo,UserProfileRepository users,MemeRepository memes,MediaStorage storage,Clock clock){this.repo=repo;this.users=users;this.memes=memes;this.storage=storage;this.clock=clock;} @Transactional public UploadResult upload(UUID userId, MultipartFile file){ if(!users.existsById(userId)) throw new ApiException(HttpStatus.NOT_FOUND,ErrorCode.USER_NOT_FOUND,"User not found"); byte[] bytes; try{bytes=file.getBytes();}catch(IOException e){throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.INVALID_FILE_CONTENT,"Cannot read file");} String ct=file.getContentType(); ImageInspector.validate(ct,bytes); String sha=ImageInspector.sha256(bytes); boolean dup=repo.existsBySha256AndStatusNot(sha,MediaAssetStatus.DELETED); UUID id=UUID.randomUUID(); String key="images/"+id; storage.put(key,new ByteArrayInputStream(bytes),bytes.length,ct); try{return new UploadResult(repo.save(new MediaAsset(id,key,safeName(file.getOriginalFilename()),ct,bytes.length,sha,userId,Instant.now(clock))),dup);}catch(RuntimeException e){try{storage.delete(key);}catch(Exception cleanup){log.warn("Failed to cleanup media object after database error for key {}",key,cleanup);}throw e;} } @Transactional(readOnly=true) public MediaContent content(UUID id, UUID requesterId){ MediaAsset a=repo.findById(id).filter(x->x.getStatus()!=MediaAssetStatus.DELETED).orElseThrow(()->new ApiException(HttpStatus.NOT_FOUND,ErrorCode.MEDIA_NOT_FOUND,"Media not found")); var meme=memes.findByMediaAssetId(id); boolean owner=requesterId!=null&&requesterId.equals(a.getUploadedBy()); boolean publicApproved=meme.map(m->m.getModerationStatus()==ModerationStatus.APPROVED).orElse(false); if(!owner&&!publicApproved) throw new ApiException(HttpStatus.FORBIDDEN,ErrorCode.ACCESS_DENIED,"Access denied"); return new MediaContent(storage.get(a.getStorageKey()),a.getContentType(),a.getSizeBytes(),'"'+a.getSha256()+'"'); } public MediaAsset getActive(UUID id){return repo.findById(id).filter(a->a.getStatus()==MediaAssetStatus.ACTIVE).orElseThrow(()->new ApiException(HttpStatus.NOT_FOUND,ErrorCode.MEDIA_NOT_FOUND,"Media not found"));} private static String safeName(String n){ if(n==null) return null; n=n.replace('\\','/'); n=n.substring(n.lastIndexOf('/')+1); return n.length()>255?n.substring(0,255):n;} public record UploadResult(MediaAsset asset, boolean duplicateDetected){} }
